import{_ as e,o as r,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Social Implications — Quick Summary","description":"","frontmatter":{},"headers":[],"relativePath":"quick-study/social-summary.md","filePath":"quick-study/social-summary.md"}'),o={name:"quick-study/social-summary.md"};function d(s,t,n,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="social-implications-—-quick-summary" tabindex="-1">Social Implications — Quick Summary <a class="header-anchor" href="#social-implications-—-quick-summary" aria-label="Permalink to &quot;Social Implications — Quick Summary&quot;">​</a></h1><p>No prose. Tables and key facts for all social implications topics.</p><hr><h2 id="copyright-intellectual-property" tabindex="-1">Copyright &amp; Intellectual Property <a class="header-anchor" href="#copyright-intellectual-property" aria-label="Permalink to &quot;Copyright &amp; Intellectual Property&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Protects</th><th>Duration</th></tr></thead><tbody><tr><td>Copyright</td><td>Creative works (music, code, writing, art)</td><td>Life + 50–70 years</td></tr><tr><td>Patent</td><td>Inventions, processes</td><td>20 years</td></tr><tr><td>Trademark</td><td>Logos, brand names</td><td>Renewable indefinitely</td></tr></tbody></table><p><strong>Copyright gives the owner exclusive right to:</strong> copy, distribute, modify, sell, or licence the work.</p><hr><h2 id="software-licences" tabindex="-1">Software Licences <a class="header-anchor" href="#software-licences" aria-label="Permalink to &quot;Software Licences&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Free?</th><th>Source?</th><th>Copy allowed?</th></tr></thead><tbody><tr><td>Proprietary</td><td>Paid</td><td>Closed</td><td>No</td></tr><tr><td>Freeware</td><td>Yes</td><td>Closed</td><td>Usually yes</td></tr><tr><td>Shareware</td><td>Trial</td><td>Closed</td><td>Trial only</td></tr><tr><td>Open source</td><td>Usually</td><td>Open</td><td>Yes (conditions)</td></tr><tr><td>Public domain</td><td>Yes</td><td>Open</td><td>Yes, no restrictions</td></tr></tbody></table><hr><h2 id="creative-commons-conditions" tabindex="-1">Creative Commons Conditions <a class="header-anchor" href="#creative-commons-conditions" aria-label="Permalink to &quot;Creative Commons Conditions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Code</th><th>Meaning</th></tr></thead><tbody><tr><td>BY</td><td>Must credit original creator</td></tr><tr><td>SA</td><td>Derivative must use same licence</td></tr><tr><td>NC</td><td>No commercial use</td></tr><tr><td>ND</td><td>No modifications allowed</td></tr></tbody></table><hr><h2 id="piracy-types" tabindex="-1">Piracy Types <a class="header-anchor" href="#piracy-types" aria-label="Permalink to &quot;Piracy Types&quot;">​</a></h2><ul><li>End-user piracy (installing on more machines than licensed)</li><li>Counterfeiting (fake copies)</li><li>Internet piracy (illegal downloads/torrents)</li><li>Hard disk loading (pre-installing on PCs for sale)</li></ul><p><strong>Consequences:</strong> fines, criminal charges, civil lawsuit, malware risk</p><hr><h2 id="cybercrime-types" tabindex="-1">Cybercrime Types <a class="header-anchor" href="#cybercrime-types" aria-label="Permalink to &quot;Cybercrime Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Crime</th><th>Description</th></tr></thead><tbody><tr><td>Hacking</td><td>Unauthorised access to computer/network</td></tr><tr><td>Virus</td><td>Attaches to files; spreads when file shared</td></tr><tr><td>Worm</td><td>Self-replicates across networks; no user action needed</td></tr><tr><td>Trojan</td><td>Disguised as legitimate software; opens backdoor</td></tr><tr><td>Ransomware</td><td>Encrypts files; demands payment</td></tr><tr><td>Spyware</td><td>Secretly monitors user; logs keystrokes</td></tr><tr><td>Phishing</td><td>Fake emails/sites to steal credentials</td></tr><tr><td>Identity theft</td><td>Using another person&#39;s personal info for fraud</td></tr><tr><td>DDoS</td><td>Flooding server with traffic to crash it</td></tr><tr><td>SQL injection</td><td>Inserting malicious SQL into web forms</td></tr><tr><td>Spoofing</td><td>Faking sender identity</td></tr><tr><td>Cyberbullying</td><td>Harassing/threatening via technology</td></tr></tbody></table><hr><h2 id="virus-vs-worm-vs-trojan" tabindex="-1">Virus vs Worm vs Trojan <a class="header-anchor" href="#virus-vs-worm-vs-trojan" aria-label="Permalink to &quot;Virus vs Worm vs Trojan&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Virus</th><th>Worm</th><th>Trojan</th></tr></thead><tbody><tr><td>Spreads by</td><td>Infected file sharing</td><td>Network, no user action</td><td>Deceptive download</td></tr><tr><td>Disguise?</td><td>No</td><td>No</td><td>Yes (looks legitimate)</td></tr><tr><td>Replicates?</td><td>Yes (needs host file)</td><td>Yes (self-contained)</td><td>No</td></tr></tbody></table><hr><h2 id="protection-measures" tabindex="-1">Protection Measures <a class="header-anchor" href="#protection-measures" aria-label="Permalink to &quot;Protection Measures&quot;">​</a></h2><p><strong>Technical:</strong></p><ul><li>Antivirus / anti-malware</li><li>Firewall (hardware or software)</li><li>Regular software updates/patches</li><li>Encryption + HTTPS</li><li>Two-factor authentication (2FA)</li><li>Strong, unique passwords</li><li>VPN</li><li>Regular backups</li></ul><p><strong>Human:</strong></p><ul><li>Don&#39;t click suspicious links</li><li>Verify sender email addresses</li><li>Never give OTPs/passwords by phone</li><li>Check URL before entering credentials (padlock, https)</li><li>Be cautious about what you share on social media</li></ul><hr><h2 id="phishing-signs" tabindex="-1">Phishing Signs <a class="header-anchor" href="#phishing-signs" aria-label="Permalink to &quot;Phishing Signs&quot;">​</a></h2><ul><li>Urgent language (&quot;Act now or your account will be closed&quot;)</li><li>Sender email doesn&#39;t match the claimed organisation</li><li>Hover over link — URL doesn&#39;t match what&#39;s shown</li><li>Grammar/spelling errors</li><li>Requests for password, OTP, or card details</li></ul><hr><h2 id="south-african-legislation" tabindex="-1">South African Legislation <a class="header-anchor" href="#south-african-legislation" aria-label="Permalink to &quot;South African Legislation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Act</th><th>Covers</th></tr></thead><tbody><tr><td>Copyright Act (1978)</td><td>Creative work protection</td></tr><tr><td>ECT Act (2002)</td><td>Cybercrime, electronic contracts</td></tr><tr><td>Cybercrimes Act (2020)</td><td>Hacking, ransomware, unlawful access</td></tr><tr><td>POPIA (2013)</td><td>Protection of personal information</td></tr></tbody></table><hr><h2 id="privacy-ethics" tabindex="-1">Privacy &amp; Ethics <a class="header-anchor" href="#privacy-ethics" aria-label="Permalink to &quot;Privacy &amp; Ethics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td>Privacy</td><td>Right to control who sees your personal information</td></tr><tr><td>Digital footprint</td><td>Trail of data left by online activity</td></tr><tr><td>Cookie</td><td>Small file stored in browser tracking visits/preferences</td></tr><tr><td>POPIA</td><td>Requires organisations to protect personal data; fines up to R10M</td></tr></tbody></table><hr><h2 id="digital-divide" tabindex="-1">Digital Divide <a class="header-anchor" href="#digital-divide" aria-label="Permalink to &quot;Digital Divide&quot;">​</a></h2><p>The gap between those with and without access to ICT:</p><p><strong>Causes:</strong> cost of devices/connectivity, lack of infrastructure, digital literacy, geography (rural vs urban)</p><p><strong>Effects:</strong> inequality in education, employment, healthcare, government services</p><hr><h2 id="environmental-impact-of-ict" tabindex="-1">Environmental Impact of ICT <a class="header-anchor" href="#environmental-impact-of-ict" aria-label="Permalink to &quot;Environmental Impact of ICT&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Detail</th></tr></thead><tbody><tr><td>E-waste</td><td>Discarded electronics contain toxic materials (lead, mercury)</td></tr><tr><td>Energy consumption</td><td>Data centres use enormous electricity</td></tr><tr><td>Carbon footprint</td><td>Manufacturing and running devices produces emissions</td></tr><tr><td>Solutions</td><td>Green data centres (renewable energy), e-waste recycling, buying refurbished</td></tr></tbody></table><hr><h2 id="ict-in-society" tabindex="-1">ICT in Society <a class="header-anchor" href="#ict-in-society" aria-label="Permalink to &quot;ICT in Society&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Technology</th><th>Social impact</th></tr></thead><tbody><tr><td>AI / automation</td><td>Job displacement; new job creation; medical diagnosis</td></tr><tr><td>Robotics</td><td>Manufacturing automation; reduces dangerous human work</td></tr><tr><td>IoT</td><td>Smart homes/cities; privacy concerns</td></tr><tr><td>Social media</td><td>Communication; cyberbullying; misinformation</td></tr><tr><td>Remote work</td><td>Flexibility; work-life balance challenges</td></tr></tbody></table>',48)])])}const p=e(o,[["render",d]]);export{m as __pageData,p as default};
